mapper.select:
select t1.*
FROM esg.tb_annual_ohs_internal_audit_plan_detail t1
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
ORDER BY t1.month ASC

mapper.update:
update esg.tb_annual_ohs_internal_audit_plan set
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
where write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}

mapper.delete:
delete from esg.tb_annual_ohs_internal_audit_plan_detail
where write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}
